          if !comp { return false }
        }
        else { result = nil }
        if let comp = self._offset_direction_constrained.value.isValueEqualOptionally(to: rhs._offset_direction_constrained.value, visited: &comppairs) {
          if !comp { return false }
        }
        else { result = nil }
        return result
      }


      //MARK: WHERE RULES (ENTITY)
      public static func WHERE_wr1(SELF: ePOGC_WITH_DIMENSION.PRef?) -> SDAI.LOGICAL {
        guard let SELF = SELF else { return SDAI.UNKNOWN }
//
        let _TEMP1 /* eEXPLICIT_CONSTRAINT.PRef? */ = SELF.GROUP_REF(eEXPLICIT_CONSTRAINT.self)
        let _TEMP2 /* SDAI.SET<eREPRESENTATION_ITEM.PRef>[0:?] ? */ = _TEMP1?.REFERENCE_ELEMENTS
        let _TEMP3 /* SDAI.INTEGER? */ = SDAI.SIZEOF( _TEMP2 )
        let _TEMP4 /* SDAI.LOGICAL */ = _TEMP3 .==. SDAI.FORCE_OPTIONAL(SDAI.INTEGER(1))
        let _TEMP5 /* eEXPLICIT_CONSTRAINT.PRef? */ = SELF.GROUP_REF(eEXPLICIT_CONSTRAINT.self)
        let _TEMP6 /* SDAI.SET<eREPRESENTATION_ITEM.PRef>[1:?] ? */ = _TEMP5?.CONSTRAINED_ELEMENTS
        let _TEMP7 /* SDAI.INTEGER? */ = SDAI.SIZEOF( _TEMP6 )
        let _TEMP8 /* SDAI.LOGICAL */ = _TEMP7 .==. SDAI.FORCE_OPTIONAL(SDAI.INTEGER(2))
        let _TEMP9 /* SDAI.LOGICAL */ = _TEMP4 || _TEMP8
        return _TEMP9
      }
      public static func WHERE_wr2(SELF: ePOGC_WITH_DIMENSION.PRef?) -> SDAI.LOGICAL {
        guard let SELF = SELF else { return SDAI.UNKNOWN }
//
        let _TEMP1 /* SDAI.LOGICAL */ = SELF.OFFSET_DIRECTION_CONSTRAINED .==. SDAI.FORCE_OPTIONAL(SDAI.LOGICAL(
          SDAI.TRUE))
        let _TEMP2 /* SDAI.LOGICAL */ =  !_TEMP1
        let _TEMP3 /* SDAI.LOGICAL */ = SELF.OFFSET_TYPE .==. SDAI.FORCE_OPTIONAL(CURVE_2D_OFFSET)
        let _TEMP4 /* SDAI.LOGICAL */ = SELF.OFFSET_TYPE .==. SDAI.FORCE_OPTIONAL(SURFACE_OFFSET)
        let _TEMP5 /* SDAI.LOGICAL */ = _TEMP3 || _TEMP4
        let _TEMP6 /* SDAI.LOGICAL */ = _TEMP2 && _TEMP5
        return _TEMP6
      }

      //EXPRESS IMPLICIT PARTIAL ENTITY CONSTRUCTOR
      /// initialize from explicit attribute values
      public init(
        OFFSET_VALUE: tPOSITIVE_LENGTH_MEASURE, 
        OFFSET_DIRECTION_CONSTRAINED: SDAI.BOOLEAN
      ) {

        self._offset_value = OFFSET_VALUE
        self._offset_direction_constrained = OFFSET_DIRECTION_CONSTRAINED

        super.init(asAbstractSuperclass:())
      }

      //PARTIAL ENTITY COPY CONSTRUCTOR
      /// copy constructor
      public required convenience init(from original:SDAI.PartialEntity) {
        let original = original as! Self
        self.init( OFFSET_VALUE: original._offset_value, OFFSET_DIRECTION_CONSTRAINED: original._offset_direction_constrained )
      }

      //p21 PARTIAL ENTITY CONSTRUCTOR
      /// initialize from ISO 10303-21 exchange structure parameters
      public required convenience init?(
        parameters: [P21Decode.ExchangeStructure.Parameter],
        exchangeStructure: P21Decode.ExchangeStructure
      ) {
        let numParams = 2
        guard parameters.count == numParams
        else { exchangeStructure.error = "number of p21 parameters(\(parameters.count)) are different from expected(\(numParams)) for partial entity(\(Self.entityName)) constructor"; return nil }

        guard case .success(let p0) = exchangeStructure.recoverRequiredParameter(as: tPOSITIVE_LENGTH_MEASURE.self, from: parameters[0])
        else { exchangeStructure.add(errorContext: "while recovering parameter [0]OFFSET_VALUE for partial entity(\(Self.entityName)) constructor"); return nil }

        guard case .success(let p1) = exchangeStructure.recoverRequiredParameter(as: SDAI.BOOLEAN.self, from: parameters[1])
        else { exchangeStructure.add(errorContext: "while recovering parameter [1]OFFSET_DIRECTION_CONSTRAINED for partial entity(\(Self.entityName)) constructor"); return nil }

        self.init( OFFSET_VALUE: p0, OFFSET_DIRECTION_CONSTRAINED: p1 )
      }
    }
  }
